import{_ as h,C as e,o as t,c as s,ag as r,j as n,a as l,E as i,w as o}from"./chunks/framework.WmBmIPw-.js";const B=JSON.parse('{"title":"分支定界算法","description":"","frontmatter":{},"headers":[],"relativePath":"or-opt/exact/branch-and-bound.md","filePath":"or-opt/exact/branch-and-bound.md","lastUpdated":1777190173000}'),c={name:"or-opt/exact/branch-and-bound.md"},u={style:{overflow:"visible","min-height":"1px","min-width":"1px","vertical-align":"-0.357ex"},xmlns:"http://www.w3.org/2000/svg",width:"2.034ex",height:"1.357ex",role:"img",focusable:"false",viewBox:"0 -442 899 599.8","aria-hidden":"true"};function b(m,a,x,T,_,Q){const d=e("mjx-assistive-mml"),p=e("mjx-container");return t(),s("div",null,[a[4]||(a[4]=r(`<h1 id="分支定界算法" tabindex="-1">分支定界算法 <a class="header-anchor" href="#分支定界算法" aria-label="Permalink to &quot;分支定界算法&quot;">​</a></h1><p>分支定界（Branch and Bound, BB）算法是求解整数规划（IP）问题的经典方法。</p><h2 id="算法步骤" tabindex="-1">算法步骤 <a class="header-anchor" href="#算法步骤" aria-label="Permalink to &quot;算法步骤&quot;">​</a></h2><p>用分支定界算法求解 max 的 IP 问题的一般步骤如下（≤ 约束）：</p><div class="custom-block algorithm"><p class="custom-block-title">▶ 分支定界算法步骤</p><h3 id="_1-初始化" tabindex="-1">1. 初始化 <a class="header-anchor" href="#_1-初始化" aria-label="Permalink to &quot;1. 初始化&quot;">​</a></h3><p>求得原问题线性松弛模型的最优解，作为节点 1。</p><h3 id="_2-设置上下界" tabindex="-1">2. 设置上下界 <a class="header-anchor" href="#_2-设置上下界" aria-label="Permalink to &quot;2. 设置上下界&quot;">​</a></h3><p>在节点 1 处：</p><ul><li>将线性松弛的最优解作为 UB（上界）</li><li>将线性松弛的解向下圆整获得的解作为 LB（下界）</li></ul><h3 id="_3-选择分支变量" tabindex="-1">3. 选择分支变量 <a class="header-anchor" href="#_3-选择分支变量" aria-label="Permalink to &quot;3. 选择分支变量&quot;">​</a></h3><p>选择分数部分最大的小数变量进行分支，构建两个将可行域按照变量的整数限制分割成两个子区域的分支约束：</p><ul><li>构造一个 ≤ 约束</li><li>构造一个 ≥ 约束</li></ul><h3 id="_4-创建分支节点" tabindex="-1">4. 创建分支节点 <a class="header-anchor" href="#_4-创建分支节点" aria-label="Permalink to &quot;4. 创建分支节点&quot;">​</a></h3><p>在 BB tree 里创建两个新的节点：</p><ul><li>一个是对应 ≥ 约束的节点</li><li>另一个是对应 ≤ 约束的节点</li></ul><h3 id="_5-求解子问题" tabindex="-1">5. 求解子问题 <a class="header-anchor" href="#_5-求解子问题" aria-label="Permalink to &quot;5. 求解子问题&quot;">​</a></h3><p>求解这两个新的节点处的线性松弛模型。</p><h3 id="_6-更新上下界与剪枝判断" tabindex="-1">6. 更新上下界与剪枝判断 <a class="header-anchor" href="#_6-更新上下界与剪枝判断" aria-label="Permalink to &quot;6. 更新上下界与剪枝判断&quot;">​</a></h3><ul><li>松弛的解是每个点的 UB</li><li>已经得到的整数解（在任意节点上）是 LB</li><li>根据查明的条件，判断该节点是否已被查明（剪枝）</li></ul><h3 id="_7-最优性判断" tabindex="-1">7. 最优性判断 <a class="header-anchor" href="#_7-最优性判断" aria-label="Permalink to &quot;7. 最优性判断&quot;">​</a></h3><p>当一个节点得到了一个整数解，并且该节点的 LB 大于或者等于其他任何叶子节点的 UB 时（也就是大于或等于全局 UB 时），我们就求得了全局最优整数解。如果该节点的解不是整数解，我们就从所有节点中 UB 最大的节点处开始分支。</p><h3 id="_8-迭代" tabindex="-1">8. 迭代 <a class="header-anchor" href="#_8-迭代" aria-label="Permalink to &quot;8. 迭代&quot;">​</a></h3><p>回到步骤（3），继续分支过程，直到找到最优解或所有节点都被查明。</p></div><h2 id="算法流程图" tabindex="-1">算法流程图 <a class="header-anchor" href="#算法流程图" aria-label="Permalink to &quot;算法流程图&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>求解线性松弛</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>设置初始 UB/LB</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>选择分支变量 → 创建两个子节点（≤ 和 ≥ 约束）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>求解子节点线性松弛</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>更新 UB/LB，判断剪枝条件</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>找到最优整数解？</span></span>
<span class="line"><span>   /        \\</span></span>
<span class="line"><span>  是        否</span></span>
<span class="line"><span>  ↓          ↓</span></span>
<span class="line"><span>结束      选择 UB 最大节点继续分支</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br></div></div><h2 id="关键概念" tabindex="-1">关键概念 <a class="header-anchor" href="#关键概念" aria-label="Permalink to &quot;关键概念&quot;">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>说明</th></tr></thead><tbody><tr><td>UB (Upper Bound)</td><td>上界，由线性松弛解给出</td></tr><tr><td>LB (Lower Bound)</td><td>下界，由找到的整数解给出</td></tr><tr><td>剪枝 (Pruning)</td><td>当节点的 UB ≤ 全局 LB 时，该节点无需再分支</td></tr><tr><td>分数变量</td><td>线性松弛解中取值为非整数的变量</td></tr></tbody></table><hr><h2 id="分支策略" tabindex="-1">分支策略 <a class="header-anchor" href="#分支策略" aria-label="Permalink to &quot;分支策略&quot;">​</a></h2><p>选择不同的分支变量会影响求解效率。以下是几种常见的分支变量选择策略：</p><h3 id="_1-最不可行分支-most-infeasible-branching" tabindex="-1">1. 最不可行分支（Most Infeasible Branching） <a class="header-anchor" href="#_1-最不可行分支-most-infeasible-branching" aria-label="Permalink to &quot;1. 最不可行分支（Most Infeasible Branching）&quot;">​</a></h3><p>选取变量取值的分数部分最接近 0.5 的变量作为下一个分支变量。</p><h3 id="_2-最大分数值分支-max-fractional-value-branching" tabindex="-1">2. 最大分数值分支（Max Fractional Value Branching） <a class="header-anchor" href="#_2-最大分数值分支-max-fractional-value-branching" aria-label="Permalink to &quot;2. 最大分数值分支（Max Fractional Value Branching）&quot;">​</a></h3><p>取最大分数值对应的变量作为分支变量。该方法甚至比随机选取还差，一般不推荐使用。</p><h3 id="_3-伪检验数分支-pseudo-reduced-cost-branching" tabindex="-1">3. 伪检验数分支（Pseudo Reduced Cost Branching） <a class="header-anchor" href="#_3-伪检验数分支-pseudo-reduced-cost-branching" aria-label="Permalink to &quot;3. 伪检验数分支（Pseudo Reduced Cost Branching）&quot;">​</a></h3><p>通过启发式方法近似评估约束的对偶价格，从而近似评估变量的检验数（因此叫伪检验数），最后根据伪检验数来评估变量分支对目标的影响，以影响大小为基准来选择分支变量。</p><h3 id="_4-强分支-strong-branching" tabindex="-1">4. 强分支（Strong Branching） <a class="header-anchor" href="#_4-强分支-strong-branching" aria-label="Permalink to &quot;4. 强分支（Strong Branching）&quot;">​</a></h3><p>在分支之前首先估计哪个分支会给目标函数带来最大的改进，然后选该变量进行分支。</p><h3 id="_5-伪成本分支-pseudo-cost-branching" tabindex="-1">5. 伪成本分支（Pseudo Cost Branching） <a class="header-anchor" href="#_5-伪成本分支-pseudo-cost-branching" aria-label="Permalink to &quot;5. 伪成本分支（Pseudo Cost Branching）&quot;">​</a></h3>`,21)),n("p",null,[a[2]||(a[2]=l("在分支的过程中记录每个被选择的分支变量 ",-1)),i(p,{class:"MathJax",jax:"SVG",style:{direction:"ltr",position:"relative"}},{default:o(()=>[(t(),s("svg",u,[...a[0]||(a[0]=[n("g",{stroke:"currentColor",fill:"currentColor","stroke-width":"0",transform:"scale(1,-1)"},[n("g",{"data-mml-node":"math"},[n("g",{"data-mml-node":"msub"},[n("g",{"data-mml-node":"mi"},[n("path",{"data-c":"1D465",d:"M52 289Q59 331 106 386T222 442Q257 442 286 424T329 379Q371 442 430 442Q467 442 494 420T522 361Q522 332 508 314T481 292T458 288Q439 288 427 299T415 328Q415 374 465 391Q454 404 425 404Q412 404 406 402Q368 386 350 336Q290 115 290 78Q290 50 306 38T341 26Q378 26 414 59T463 140Q466 150 469 151T485 153H489Q504 153 504 145Q504 144 502 134Q486 77 440 33T333 -11Q263 -11 227 52Q186 -10 133 -10H127Q78 -10 57 16T35 71Q35 103 54 123T99 143Q142 143 142 101Q142 81 130 66T107 46T94 41L91 40Q91 39 97 36T113 29T132 26Q168 26 194 71Q203 87 217 139T245 247T261 313Q266 340 266 352Q266 380 251 392T217 404Q177 404 142 372T93 290Q91 281 88 280T72 278H58Q52 284 52 289Z",style:{"stroke-width":"3"}})]),n("g",{"data-mml-node":"mi",transform:"translate(605,-150) scale(0.707)"},[n("path",{"data-c":"1D456",d:"M184 600Q184 624 203 642T247 661Q265 661 277 649T290 619Q290 596 270 577T226 557Q211 557 198 567T184 600ZM21 287Q21 295 30 318T54 369T98 420T158 442Q197 442 223 419T250 357Q250 340 236 301T196 196T154 83Q149 61 149 51Q149 26 166 26Q175 26 185 29T208 43T235 78T260 137Q263 149 265 151T282 153Q302 153 302 143Q302 135 293 112T268 61T223 11T161 -11Q129 -11 102 10T74 74Q74 91 79 106T122 220Q160 321 166 341T173 380Q173 404 156 404H154Q124 404 99 371T61 287Q60 286 59 284T58 281T56 279T53 278T49 278T41 278H27Q21 284 21 287Z",style:{"stroke-width":"3"}})])])])],-1)])])),i(d,{unselectable:"on",display:"inline",style:{top:"0px",left:"0px",clip:"rect(1px, 1px, 1px, 1px)","-webkit-touch-callout":"none","-webkit-user-select":"none","-khtml-user-select":"none","-moz-user-select":"none","-ms-user-select":"none","user-select":"none",position:"absolute",padding:"1px 0px 0px 0px",border:"0px",display:"block",width:"auto",overflow:"hidden"}},{default:o(()=>[...a[1]||(a[1]=[n("math",{xmlns:"http://www.w3.org/1998/Math/MathML"},[n("msub",null,[n("mi",null,"x"),n("mi",null,"i")])],-1)])]),_:1})]),_:1}),a[3]||(a[3]=l(" 分支前后的目标函数的变化，在当前时刻选择下一个分支变量时，根据每个取值为小数的变量的以往的分支相关信息，选择预期会给目标函数带来最大单位改善的变量作为下一个分支变量。",-1))]),a[5]||(a[5]=r('<hr><h2 id="节点遍历策略" tabindex="-1">节点遍历策略 <a class="header-anchor" href="#节点遍历策略" aria-label="Permalink to &quot;节点遍历策略&quot;">​</a></h2><p>在 BB tree 搜索的过程中，选择 UB 最大的未被探明的叶子节点为下一个分支节点并不总是最好的。以下是几种常见的节点遍历策略：</p><table tabindex="0"><thead><tr><th>策略</th><th>描述</th><th>特点</th></tr></thead><tbody><tr><td>深度优先搜索（Depth First Search）</td><td>优先探索深层节点</td><td>能够更快地找到可行解</td></tr><tr><td>广度优先搜索（Breadth First Search）</td><td>按层级探索节点</td><td>可以更快地剪掉更多的分支</td></tr><tr><td>最好界限优先搜索（Best First Search）</td><td>LB 或 UB 最好的节点首先被探索</td><td>通常能更快找到最优解</td></tr><tr><td>其他启发式规则</td><td>结合具体问题特点的自定义策略</td><td>灵活性强</td></tr></tbody></table>',4))])}const f=h(c,[["render",b]]);export{B as __pageData,f as default};
